// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('validate column 評価判断指数', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('validate column 評価判断指数', async function() {
    // Test name: validate column 評価判断指数
    // Step # | name | target | value
    // 1 | open | http://localhost:4200/user/evaluation-8-10/5 | 
    await driver.get("http://localhost:4200/user/evaluation-8-10/5");

    // 2 | waitForElementPresent | xpath=//button[contains(.,'追 加')] | 30000
    await driver.wait(until.elementLocated(By.xpath("//button[contains(.,\'追 加\')]")), 30000);

    // 3 | click | xpath=//span[contains(.,'追 加')] | 
    await driver.findElement(By.xpath("//span[contains(.,\'追 加\')]")).click();

    // 4 | click | xpath=//span[contains(.,'追 加')] | 
    await driver.findElement(By.xpath("//span[contains(.,\'追 加\')]")).click();

    // 5 | click | xpath=(//button[@type='button'])[10] | 
    await driver.findElement(By.xpath("(//button[@type=\'button\'])[10]")).click();

    // 6 | mouseOver | xpath=//div[@id='rc-tabs-1-panel-1']/form/div/div/div/div/div/div/table/tbody/tr/td/button | 
    {
      const element = await driver.findElement(By.xpath("//div[@id=\'rc-tabs-1-panel-1\']/form/div/div/div/div/div/div/table/tbody/tr/td/button"));
      await driver.actions({ bridge: true }).moveToElement(element).perform();
    }

    // 7 | mouseOut | css=.ant-table-row-expand-icon-expanded | 
    {
      const element = await driver.findElement(By.CSS_SELECTOR, "body");
      await driver.actions({ bridge: true }).moveToElement(element, 0, 0).perform();
    }

    // 8 | click | id=index_0_1 | 
    await driver.findElement(By.id("index_0_1")).click();

    // 9 | click | id=index_0_1 | 
    await driver.findElement(By.id("index_0_1")).click();

    // 10 | type | id=index_0_1 | test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1t
    await driver.findElement(By.id("index_0_1")).sendKeys("test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1test1t");

    // 11 | click | css=.ant-form-item-explain-error | 
    await driver.findElement(By.css(".ant-form-item-explain-error")).click();

    // 12 | verifyText | css=.ant-form-item-explain-error | ko nhap qua 200 ki tu
    assert(await driver.findElement(By.css(".ant-form-item-explain-error")).getText() == "ko nhap qua 200 ki tu");

    // 13 | click | id=index_0_1 | 
    await driver.findElement(By.id("index_0_1")).click();

    // 14 | type | id=index_0_1 |  
    await driver.findElement(By.id("index_0_1")).sendKeys(" ");

    // 15 | click | css=.ant-form-item-explain-error | 
    await driver.findElement(By.css(".ant-form-item-explain-error")).click();

    // 16 | verifyText | css=.ant-form-item-explain-error | ko de trong
    assert(await driver.findElement(By.css(".ant-form-item-explain-error")).getText() == "ko de trong");
  });
});
